use std::collections::{BTreeMap, BTreeSet};
use std::fs::{create_dir_all, write};
use std::path::Path;

use dinoco_compiler::{
    FunctionCall, ParsedField, ParsedFieldDefault, ParsedFieldType, ParsedRelation, ParsedSchema, ParsedTable,
};

use super::helpers::{
    default_value_expr, filter_type, relation_fields, relation_target, rust_scalar_base_type, rust_scalar_type,
    scalar_fields, to_snake_case,
};
use super::relations::{RelationCardinality, collect_join_tables, resolve_relation};
use super::render_dinoco::render_dinoco_module;
use super::render_enums::render_enums;

const GENERATED_FILE_BANNER: &str = "// ==============================================================\n\
// =================== DINOCO MANAGED FILE =======================\n\
// ==============================================================\n\
// This file is generated and managed by Dinoco.\n\
// Do not edit this file manually.\n\
// Any manual changes will be overwritten the next time Dinoco runs.\n\
// ==============================================================\n\n";
const GENERATED_FILE_LINTS: &str = "#![allow(dead_code)]\n#![allow(non_camel_case_types)]\n#![allow(non_snake_case)]\n#![allow(non_upper_case_globals)]\n#![allow(unused_imports)]\n#![allow(unused_variables)]\n\n";

pub fn generate_models(schema: ParsedSchema) {
    let dinoco_dir = Path::new("dinoco");
    let output_dir = dinoco_dir.join("models");

    if output_dir.exists() {
        std::fs::remove_dir_all(&output_dir).unwrap();
    }

    create_dir_all(&output_dir).unwrap();
    write(dinoco_dir.join("mod.rs"), render_dinoco_module(&schema)).unwrap();

    let mut module_exports = Vec::new();
    let mut enum_names = Vec::new();

    if !schema.enums.is_empty() {
        let enum_file = render_enums(&schema);

        write(output_dir.join("enums.rs"), enum_file).unwrap();
        module_exports.push("pub mod enums;".to_string());
        module_exports.push("pub use enums::*;".to_string());

        enum_names.extend(schema.enums.iter().map(|item| item.name.clone()));
    }

    for table in &schema.tables {
        let file_name = to_snake_case(&table.name);
        let file_path = output_dir.join(format!("{file_name}.rs"));
        let model_file = render_model(table, &table.name, &schema, &enum_names);

        write(file_path, model_file).unwrap();
        module_exports.push(format!("pub mod {file_name};"));
        module_exports.push(format!("pub use {file_name}::*;"));
    }

    for join_table in collect_join_tables(&schema) {
        let file_name = to_snake_case(&join_table.model_name);
        let file_path = output_dir.join(format!("{file_name}.rs"));
        let model_file = render_model(&join_table.table, &join_table.model_name, &schema, &enum_names);

        write(file_path, model_file).unwrap();
        module_exports.push(format!("pub mod {file_name};"));
        module_exports.push(format!("pub use {file_name}::*;"));
    }

    write(
        output_dir.join("mod.rs"),
        format!("{GENERATED_FILE_BANNER}{GENERATED_FILE_LINTS}{}", module_exports.join("\n")),
    )
    .unwrap();
}

fn render_model(table: &ParsedTable, model_name: &str, schema: &ParsedSchema, enum_names: &[String]) -> String {
    let name = model_name;
    let fields = &table.fields;
    let scalar_fields = scalar_fields(fields);
    let insert_fields = scalar_fields
        .iter()
        .copied()
        .filter(|field| !matches!(field.default_value, ParsedFieldDefault::Function(FunctionCall::AutoIncrement)))
        .collect::<Vec<_>>();
    let update_fields = scalar_fields
        .iter()
        .copied()
        .filter(|field| !table.primary_key_fields.iter().any(|primary_key| primary_key == &field.name))
        .collect::<Vec<_>>();
    let primary_key_fields = scalar_fields
        .iter()
        .copied()
        .filter(|field| table.primary_key_fields.iter().any(|primary_key| primary_key == &field.name))
        .collect::<Vec<_>>();
    let auto_increment_primary_key_field = primary_key_fields.iter().copied().find(|field| {
        matches!(field.default_value, ParsedFieldDefault::Function(FunctionCall::AutoIncrement))
    });
    let relation_fields = relation_fields(fields);
    let relation_imports = relation_fields
        .iter()
        .filter_map(|field| {
            let ParsedFieldType::Relation(target) = &field.field_type else {
                return None;
            };

            if target == name {
                return None;
            }

            Some(format!("{}::{}", to_snake_case(target), target))
        })
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();

    let mut output = String::from(GENERATED_FILE_BANNER);

    output.push_str(GENERATED_FILE_LINTS);

    output.push_str(
        "use dinoco::{AdapterDialect, FindAndUpdateModel, InsertModel, IntoDinocoValue, Model, Projection, RelationField, RelationMutationModel, RelationMutationWhere, RelationScalarField, RelationWritePlan, Rowable, ScalarField, UpdateField, UpdateModel};\n",
    );

    if !relation_imports.is_empty() {
        output.push_str(&format!("use super::{{{}}};\n", relation_imports.join(", ")));
    }

    output.push('\n');
    output.push_str("#[derive(Debug, Clone, dinoco::serde::Serialize, dinoco::serde::Deserialize, Rowable)]\n");
    output.push_str("#[serde(crate = \"dinoco::serde\")]\n");
    output.push_str(&format!("pub struct {} {{\n", name));

    for field in &scalar_fields {
        output.push_str(&format!("    pub {}: {},\n", field.name, rust_scalar_type(field, enum_names)));
    }

    output.push_str("}\n\n");
    output.push_str(&format!("impl {} {{\n", name));
    output.push_str("    pub fn new() -> Self {\n");
    output.push_str("        Self::default()\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl Default for {} {{\n", name));
    output.push_str("    fn default() -> Self {\n");
    output.push_str("        Self {\n");

    for field in &scalar_fields {
        output.push_str(&format!("            {}: {},\n", field.name, default_value_expr(field, enum_names)));
    }

    output.push_str("        }\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("pub struct {}Where {{\n", name));

    for field in &scalar_fields {
        output.push_str(&format!("    pub {}: ScalarField<{}>,\n", field.name, filter_type(field, enum_names)));
    }

    output.push_str("}\n\n");
    output.push_str(&format!("pub struct {}Update {{\n", name));

    for field in &update_fields {
        output.push_str(&format!("    pub {}: UpdateField<{}>,\n", field.name, filter_type(field, enum_names)));
    }

    output.push_str("}\n\n");
    output.push_str(&render_relation_mutation_where(table, &scalar_fields, enum_names));
    output.push_str(&format!("pub struct {}Include {}\n\n", name, "{}"));
    output.push_str(&format!("pub struct {}Relations {}\n\n", name, "{}"));
    output.push_str(&format!("impl Projection<{}> for {} {{\n", name, name));
    output.push_str("    fn columns() -> &'static [&'static str] {\n");
    output.push_str("        &[\n");

    for field in &scalar_fields {
        output.push_str(&format!("            \"{}\",\n", field.name));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl InsertModel for {} {{\n", name));
    output.push_str("    fn insert_columns() -> &'static [&'static str] {\n");
    output.push_str("        &[\n");

    for field in &insert_fields {
        output.push_str(&format!("            \"{}\",\n", field.name));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n\n");
    output.push_str("    fn into_insert_row(self) -> Vec<dinoco::DinocoValue> {\n");
    output.push_str("        vec![\n");

    for field in &insert_fields {
        output.push_str(&format!("            self.{}.into_dinoco_value(),\n", field.name));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n\n");
    output.push_str("    fn insert_identity_conditions(&self) -> Vec<dinoco::Expression> {\n");
    output.push_str("        vec![\n");

    for field in &primary_key_fields {
        output.push_str(&format!(
            "            dinoco::Expression::Column({:?}.to_string()).eq(self.{}.clone().into_dinoco_value()),\n",
            field.name, field.name
        ));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n\n");
    if let Some(field) = auto_increment_primary_key_field {
        output.push_str("    fn auto_increment_primary_key_column() -> Option<&'static str> {\n");
        output.push_str(&format!("        Some({:?})\n", field.name));
        output.push_str("    }\n\n");
    }
    output.push_str("    fn validate_insert(&self) -> dinoco::DinocoResult<()> {\n");

    let insert_validations = render_insert_validations(table, &insert_fields);
    if insert_validations.is_empty() {
        output.push_str("        Ok(())\n");
    } else {
        output.push_str(&insert_validations);
        output.push_str("        Ok(())\n");
    }

    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl UpdateModel for {} {{\n", name));
    output.push_str("    fn update_columns() -> &'static [&'static str] {\n");
    output.push_str("        &[\n");

    for field in &update_fields {
        output.push_str(&format!("            \"{}\",\n", field.name));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n\n");
    output.push_str("    fn into_update_row(self) -> Vec<dinoco::DinocoValue> {\n");
    output.push_str("        vec![\n");

    for field in &update_fields {
        output.push_str(&format!("            self.{}.into_dinoco_value(),\n", field.name));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n\n");
    output.push_str("    fn update_identity_conditions(&self) -> Vec<dinoco::Expression> {\n");
    output.push_str("        vec![\n");

    for field in &primary_key_fields {
        output.push_str(&format!(
            "            dinoco::Expression::Column({:?}.to_string()).eq(self.{}.clone().into_dinoco_value()),\n",
            field.name, field.name
        ));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n\n");
    output.push_str("    fn validate_update(&self) -> dinoco::DinocoResult<()> {\n");
    output.push_str("        Ok(())\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl Default for {}Where {{\n", name));
    output.push_str("    fn default() -> Self {\n");
    output.push_str("        Self {\n");

    for field in &scalar_fields {
        output.push_str(&format!("            {}: ScalarField::new(\"{}\"),\n", field.name, field.name));
    }

    output.push_str("        }\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl Default for {}Update {{\n", name));
    output.push_str("    fn default() -> Self {\n");
    output.push_str("        Self {\n");

    for field in &update_fields {
        output.push_str(&format!("            {}: UpdateField::new(\"{}\"),\n", field.name, field.name));
    }

    output.push_str("        }\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl Default for {}Include {{\n", name));
    output.push_str("    fn default() -> Self {\n");
    output.push_str("        Self {}\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl Default for {}Relations {{\n", name));
    output.push_str("    fn default() -> Self {\n");
    output.push_str("        Self {}\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");
    output.push_str(&format!("impl {}Include {{\n", name));

    for field in &relation_fields {
        output.push_str(&format!("    pub fn {}(&self) -> RelationField<{}> {{\n", field.name, relation_target(field)));
        output.push_str(&format!("        RelationField::new(\"{}\")\n", field.name));
        output.push_str("    }\n");
    }

    output.push_str("}\n\n");
    output.push_str(&format!("impl {}Relations {{\n", name));

    for field in &relation_fields {
        let ParsedFieldType::Relation(target_name) = &field.field_type else {
            continue;
        };

        output.push_str(&format!(
            "    pub fn {}(&self) -> RelationMutationWhere<super::{}::{}RelationWhere> {{\n",
            field.name,
            to_snake_case(target_name),
            target_name
        ));
        output.push_str(&format!(
            "        super::{}::{}RelationWhere::new({:?})\n",
            to_snake_case(target_name),
            target_name,
            field.name
        ));
        output.push_str("    }\n");
    }

    output.push_str("}\n\n");
    output.push_str(&render_relation_loaders(table, schema));
    output.push_str(&render_relation_count_loaders(table, schema));
    output.push_str(&render_relation_mutations(table, schema));
    output.push_str(&render_insert_relations(table, schema));
    output.push_str(&format!("impl Model for {} {{\n", name));
    output.push_str(&format!("    type Include = {}Include;\n", name));
    output.push_str(&format!("    type Where = {}Where;\n\n", name));
    output.push_str("    fn table_name() -> &'static str {\n");
    output.push_str(&format!("        \"{}\"\n", table.database_name));
    output.push_str("    }\n");
    output.push_str("}\n");
    output.push_str("\n");
    output.push_str(&format!("impl RelationMutationModel for {} {{\n", name));
    output.push_str(&format!("    type Relations = {}Relations;\n\n", name));
    output.push_str(
        "    fn relation_write_plan(target: dinoco::RelationMutationTarget) -> Option<RelationWritePlan> {\n",
    );
    output.push_str("        match target.relation_name {\n");

    for field in &relation_fields {
        let Some(relation) = resolve_relation(table, field, schema) else {
            continue;
        };

        let RelationCardinality::ManyToMany { join_table_name, current_join_column, target_join_column } =
            relation.cardinality
        else {
            continue;
        };

        output.push_str(&format!(
            "            {:?} => Some(RelationWritePlan {{ join_table_name: {:?}, source_table_name: {:?}, source_key_column: {:?}, source_join_column: {:?}, target_table_name: {:?}, target_key_column: {:?}, target_join_column: {:?}, target_expression: target.expression }}),\n",
            field.name,
            join_table_name,
            table.database_name,
            relation.local_key_field.name,
            current_join_column,
            relation.target_table_name,
            relation.remote_key_field.name,
            target_join_column
        ));
    }

    output.push_str("            _ => None,\n");
    output.push_str("        }\n");
    output.push_str("    }\n");
    output.push_str("}\n");
    output.push_str("\n");
    output.push_str(&format!("impl FindAndUpdateModel for {} {{\n", name));
    output.push_str(&format!("    type Update = {}Update;\n\n", name));
    output.push_str("    fn primary_key_columns() -> &'static [&'static str] {\n");
    output.push_str("        &[\n");

    for field in &primary_key_fields {
        output.push_str(&format!("            \"{}\",\n", field.name));
    }

    output.push_str("        ]\n");
    output.push_str("    }\n");
    output.push_str("}\n");

    output
}

fn render_insert_validations(table: &ParsedTable, insert_fields: &[&dinoco_compiler::ParsedField]) -> String {
    let mut output = String::new();

    for field in insert_fields {
        if field.is_optional || !matches!(field.default_value, ParsedFieldDefault::NotDefined) {
            continue;
        }

        let model_name = &table.name;
        let field_name = &field.name;

        match field.field_type {
            ParsedFieldType::String => {
                output.push_str(&format!(
                    "        if self.{field_name}.trim().is_empty() {{\n            return Err(dinoco::DinocoError::ParseError(\"Field '{model_name}.{field_name}' is required for insert and cannot be empty\".to_string()));\n        }}\n"
                ));
            }
            ParsedFieldType::Json => {
                output.push_str(&format!(
                    "        if matches!(self.{field_name}, dinoco::JsonValue::Null) {{\n            return Err(dinoco::DinocoError::ParseError(\"Field '{model_name}.{field_name}' is required for insert and cannot be null\".to_string()));\n        }}\n"
                ));
            }
            _ => {}
        }
    }

    output
}

fn render_relation_mutation_where(
    table: &ParsedTable,
    scalar_fields: &[&ParsedField],
    enum_names: &[String],
) -> String {
    let mut output = String::new();

    output.push_str(&format!("pub struct {}RelationWhere {{\n", table.name));

    for field in scalar_fields {
        output.push_str(&format!("    pub {}: RelationScalarField<{}>,\n", field.name, filter_type(field, enum_names)));
    }

    output.push_str("}\n\n");
    output.push_str(&format!("impl {}RelationWhere {{\n", table.name));
    output.push_str("    pub fn new(relation_name: &'static str) -> RelationMutationWhere<Self> {\n");
    output.push_str("        RelationMutationWhere::new(Self {\n");

    for field in scalar_fields {
        output.push_str(&format!(
            "            {}: RelationScalarField::new(relation_name, {:?}),\n",
            field.name, field.name
        ));
    }

    output.push_str("        })\n");
    output.push_str("    }\n");
    output.push_str("}\n\n");

    output
}

fn render_relation_mutations(_table: &ParsedTable, _schema: &ParsedSchema) -> String {
    String::new()
}

fn render_relation_loaders(table: &ParsedTable, schema: &ParsedSchema) -> String {
    let mut output = String::new();

    for field in relation_fields(&table.fields) {
        let Some(relation) = resolve_relation(table, field, schema) else {
            continue;
        };

        let loader_name = format!("__dinoco_load_{}", field.name);
        let local_key_ty = rust_scalar_base_type(relation.local_key_field, &[]);
        let remote_key_ty = rust_scalar_base_type(relation.remote_key_field, &[]);
        let target_model = relation_target(field);
        let remote_key_ident = &relation.remote_key_field.name;
        let statement_table = &relation.target_table_name;

        let block = match relation.cardinality {
            RelationCardinality::Many => render_many_loader(
                table.name.as_str(),
                &loader_name,
                &local_key_ty,
                &target_model,
                remote_key_ident,
                statement_table,
            ),
            RelationCardinality::OptionalOne => render_optional_loader(
                table.name.as_str(),
                &loader_name,
                &local_key_ty,
                &target_model,
                remote_key_ident,
                statement_table,
            ),
            RelationCardinality::ManyToMany {
                ref join_table_name,
                ref current_join_column,
                ref target_join_column,
            } => render_many_to_many_loader(
                table.name.as_str(),
                &loader_name,
                &local_key_ty,
                &remote_key_ty,
                &target_model,
                remote_key_ident,
                statement_table,
                join_table_name,
                current_join_column,
                target_join_column,
            ),
        };

        output.push_str(&block);
    }

    output
}

fn render_relation_count_loaders(table: &ParsedTable, schema: &ParsedSchema) -> String {
    let mut output = String::new();

    for field in relation_fields(&table.fields) {
        let Some(relation) = resolve_relation(table, field, schema) else {
            continue;
        };

        let loader_name = format!("__dinoco_count_{}", field.name);
        let local_key_ty = rust_scalar_base_type(relation.local_key_field, &[]);
        let remote_key_ty = rust_scalar_base_type(relation.remote_key_field, &[]);
        let remote_key_ident = &relation.remote_key_field.name;
        let statement_table = &relation.target_table_name;

        let block = match relation.cardinality {
            RelationCardinality::Many | RelationCardinality::OptionalOne => render_relation_count_loader(
                table.name.as_str(),
                &loader_name,
                &local_key_ty,
                remote_key_ident,
                statement_table,
            ),
            RelationCardinality::ManyToMany {
                ref join_table_name,
                ref current_join_column,
                ref target_join_column,
            } => render_many_to_many_count_loader(
                table.name.as_str(),
                &loader_name,
                &local_key_ty,
                &remote_key_ty,
                remote_key_ident,
                statement_table,
                join_table_name,
                current_join_column,
                target_join_column,
            ),
        };

        output.push_str(&block);
    }

    output
}

fn render_insert_relations(table: &ParsedTable, schema: &ParsedSchema) -> String {
    let mut output = String::new();
    let mut relations = Vec::new();

    for field in relation_fields(&table.fields) {
        if !matches!(
            field.relation,
            ParsedRelation::OneToMany(_) | ParsedRelation::OneToOneInverse(_) | ParsedRelation::ManyToMany(_)
        ) {
            continue;
        }

        let Some(relation) = resolve_relation(table, field, schema) else {
            continue;
        };

        let target_model = relation_target(field);
        relations.push((field, relation, target_model));
    }

    let mut relation_counts = BTreeMap::<String, usize>::new();

    for (_, _, target_model) in &relations {
        *relation_counts.entry(target_model.clone()).or_default() += 1;
    }

    for (_field, relation, target_model) in relations {
        if relation_counts.get(&target_model).copied().unwrap_or_default() > 1 {
            continue;
        }

        output.push_str(&format!("impl dinoco::InsertRelation<{}> for {} {{\n", target_model, table.name));
        match relation.cardinality {
            RelationCardinality::ManyToMany {
                ref join_table_name,
                ref current_join_column,
                ref target_join_column,
            } => {
                output.push_str(&format!(
                    "    fn relation_links(&self, item: &{}) -> Vec<dinoco::RelationLinkPlan> {{\n",
                    target_model
                ));
                output.push_str("        vec![dinoco::RelationLinkPlan {\n");
                output.push_str(&format!("            table_name: {:?},\n", join_table_name));
                output.push_str(&format!(
                    "            columns: &[{:?}, {:?}],\n",
                    current_join_column, target_join_column
                ));
                output.push_str(&format!(
                    "            row: vec![self.{}.clone().into_dinoco_value(), item.{}.clone().into_dinoco_value()],\n",
                    relation.local_key_field.name, relation.remote_key_field.name
                ));
                output.push_str("        }]\n");
                output.push_str("    }\n");
            }
            _ => {
                output.push_str(&format!("    fn bind_relation(&self, item: &mut {}) {{\n", target_model));
                if relation.remote_key_field.is_optional {
                    output.push_str(&format!(
                        "        item.{} = Some(self.{}.clone());\n",
                        relation.remote_key_field.name, relation.local_key_field.name
                    ));
                } else {
                    output.push_str(&format!(
                        "        item.{} = self.{}.clone();\n",
                        relation.remote_key_field.name, relation.local_key_field.name
                    ));
                }
                output.push_str("    }\n");
            }
        }
        output.push_str("}\n\n");

        match relation.cardinality {
            RelationCardinality::ManyToMany { .. } => {
                output
                    .push_str(&format!("impl dinoco::InsertConnection<{}> for {} {{}}\n\n", target_model, table.name));
            }
            _ => {
                let target_table_name = target_model.rsplit("::").next().unwrap_or(&target_model);
                let Some(target_table) = schema.tables.iter().find(|candidate| candidate.name == target_table_name)
                else {
                    continue;
                };

                if target_table.primary_key_fields.is_empty() {
                    continue;
                }

                output.push_str(&format!("impl dinoco::InsertConnection<{}> for {} {{\n", target_model, table.name));
                output.push_str(&format!(
                    "    fn connection_updates(&self, item: &{}) -> Vec<dinoco::ConnectionUpdatePlan> {{\n",
                    target_model
                ));
                output.push_str("        vec![dinoco::ConnectionUpdatePlan {\n");
                output.push_str(&format!("            table_name: {:?},\n", relation.target_table_name));
                output.push_str(&format!("            columns: &[{:?}],\n", relation.remote_key_field.name));
                output.push_str(&format!(
                    "            row: vec![self.{}.clone().into_dinoco_value()],\n",
                    relation.local_key_field.name
                ));
                output.push_str("            conditions: vec![\n");

                for primary_key in &target_table.primary_key_fields {
                    output.push_str(&format!(
                        "                dinoco::Expression::Column({:?}.to_string()).eq(item.{}.clone().into_dinoco_value()),\n",
                        primary_key, primary_key
                    ));
                }

                output.push_str("            ],\n");
                output.push_str("        }]\n");
                output.push_str("    }\n");
                output.push_str("}\n\n");
            }
        }
    }

    output
}

fn render_many_loader(
    model_name: &str,
    loader_name: &str,
    local_key_ty: &str,
    target_model: &str,
    remote_key_ident: &str,
    statement_table: &str,
) -> String {
    format!(
        "impl {model_name} {{\n    pub fn {loader_name}<'a, P, C, A>(\n        item_keys: Vec<Option<{local_key_ty}>>,\n        include: &'a dinoco::IncludeNode,\n        client: &'a dinoco::DinocoClient<A>,\n        read_mode: dinoco::ReadMode,\n        relation_field: impl Fn(&mut P) -> &mut Vec<C> + Copy + 'a,\n    ) -> dinoco::IncludeLoaderFuture<'a, P>\n    where\n        A: dinoco::DinocoAdapter,\n        C: dinoco::Projection<{target_model}>,\n    {{\n        Box::pin(async move {{\n            use std::collections::HashMap;\n\n            struct DinocoChildRow<C> {{\n                item: C,\n                relation_key: {local_key_ty},\n            }}\n\n            impl<C> dinoco::DinocoRow for DinocoChildRow<C>\n            where\n                C: dinoco::Projection<{target_model}>,\n            {{\n                fn from_row<R: dinoco::DinocoGenericRow>(row: &R) -> dinoco::DinocoResult<Self> {{\n                    Ok(Self {{\n                        item: C::from_row(row)?,\n                        relation_key: row.get(C::columns().len())?,\n                    }})\n                }}\n            }}\n\n            let keys = item_keys.iter().flatten().cloned().collect::<Vec<_>>();\n\n            if keys.is_empty() {{\n                return Ok(Box::new(|_: &mut [P]| {{}}) as dinoco::IncludeApplier<'a, P>);\n            }}\n\n            let base_statement = include.statement.clone().unwrap_or_else(|| dinoco::SelectStatement::new().from({statement_table:?}).select(C::columns()));\n            let adapter = client.read_adapter(false);\n            let mut statement = base_statement;\n            let mut select_columns = statement.select.clone();\n\n            if select_columns.is_empty() {{\n                select_columns = C::columns().iter().map(|column| column.to_string()).collect::<Vec<_>>();\n            }}\n\n            select_columns.push({remote_key_ident:?}.to_string());\n            statement.select = select_columns;\n            statement.conditions.push(dinoco::Expression::Column({remote_key_ident:?}.to_string()).in_values(keys.iter().cloned().map(dinoco::IntoDinocoValue::into_dinoco_value).collect()));\n\n            let (sql, params) = if statement.limit.is_some() || statement.skip.is_some() {{\n                dinoco::QueryBuilder::build_partitioned_select(adapter.dialect(), &statement, {remote_key_ident:?}, \"__dinoco_row_num\")\n            }} else {{\n                dinoco::QueryBuilder::build_select(adapter.dialect(), &statement)\n            }};\n            let child_rows = adapter.query_as::<DinocoChildRow<C>>(&sql, &params).await?;\n            let relation_keys = child_rows.iter().map(|row| row.relation_key.clone()).collect::<Vec<_>>();\n            let mut children = child_rows.into_iter().map(|row| row.item).collect::<Vec<_>>();\n\n            C::load_includes(&mut children, &include.includes, client, read_mode).await?;\n            C::load_counts(&mut children, &include.counts, client, read_mode).await?;\n\n            let mut grouped: HashMap<{local_key_ty}, Vec<C>> = HashMap::new();\n\n            for (relation_key, child) in relation_keys.into_iter().zip(children.into_iter()) {{\n                grouped.entry(relation_key).or_default().push(child);\n            }}\n\n            Ok(Box::new(move |items: &mut [P]| {{\n                for (item, key) in items.iter_mut().zip(item_keys.into_iter()) {{\n                    *relation_field(item) = key.and_then(|key| grouped.remove(&key)).unwrap_or_default();\n                }}\n            }}) as dinoco::IncludeApplier<'a, P>)\n        }})\n    }}\n}}\n\n"
    )
}

